  app.patch("/api/participants/:id", async (req, res) => {
    try {
      const updates: any = {};
      if (req.body.name) updates.name = req.body.name;
      if (req.body.email !== undefined) updates.email = req.body.email;
      if (req.body.newsletterOptIn !== undefined) updates.newsletterOptIn = !!req.body.newsletterOptIn;
      if (req.body.preferredRatingScale !== undefined) {
        const s = req.body.preferredRatingScale;
        if (s === null) {
          updates.preferredRatingScale = null;
        } else if ([5, 10, 20, 100].includes(Number(s))) {
          updates.preferredRatingScale = Number(s);
        } else {
          return res.status(400).json({ message: "Invalid rating scale. Must be 5, 10, 20, 100 or null." });
        }
      }

      if (req.body.pin !== undefined) {
        if (!req.body.pin || req.body.pin.length < 4 || req.body.pin.length > 64) {
          return res.status(400).json({ message: "Password must be 4–64 characters" });
        }
        const existing = await storage.getParticipant(req.params.id);
        if (!existing) return res.status(404).json({ message: "Not found" });
        if (existing.pin) {
          if (!req.body.currentPin) {
            return res.status(400).json({ message: "Current password is required to change password" });
          }
          if (!(await verifyPassword(req.body.currentPin, existing.pin))) {
            return res.status(401).json({ message: "Current password is incorrect" });
          }
        }
        updates.pin = await hashPassword(req.body.pin);
      }

      const participant = await storage.updateParticipant(req.params.id, updates);
      if (!participant) return res.status(404).json({ message: "Not found" });
      res.json(participant);
    } catch (e: any) {
      res.status(400).json({ message: e.message });
    }
  });

