  app.delete("/api/tastings/:tastingId/voice-memos/:memoId", async (req, res) => {
    try {
      const participantId = req.headers["x-participant-id"] as string | undefined;
      if (!participantId) return res.status(401).json({ message: "Missing participant ID" });

      const memo = await storage.getVoiceMemosForTasting(req.params.tastingId);
      const target = memo.find(m => m.id === req.params.memoId);
      if (!target) return res.status(404).json({ message: "Voice memo not found" });

      const requester = await storage.getParticipant(participantId);
      const tasting = await storage.getTasting(req.params.tastingId);
      const isOwner = target.participantId === participantId;
      const isHost = tasting?.hostId === participantId;
      const isAdmin = requester?.role === "admin";
      if (!isOwner && !isHost && !isAdmin) return res.status(403).json({ message: "Not authorized to delete this memo" });

      await storage.deleteVoiceMemo(req.params.memoId, target.participantId);
      res.json({ success: true });
    } catch (e: any) {
      res.status(500).json({ message: "Could not delete voice memo" });
    }
  });

  // ===== CONNOISSEUR REPORTS =====

  type LiveWhiskySummary = {
    name: string;
    distillery?: string;
    region?: string;
    scores: { nose: number | null; taste: number | null; finish: number | null; overall: number | null };
    flavors: string[];
    vsGroupOverall: number | null;
  };

  function extractSnapshotWhiskySummaries(snapshot: unknown): LiveWhiskySummary[] {
    if (!snapshot || typeof snapshot !== "object") return [];
    const candidate = (snapshot as { whiskySummaries?: unknown }).whiskySummaries;
    return Array.isArray(candidate) ? (candidate as LiveWhiskySummary[]) : [];
  }

  type LiveExtremeWhisky = { name: string; score: number | null } | null;
  type LiveHighestLowest = { highestWhisky: LiveExtremeWhisky; lowestWhisky: LiveExtremeWhisky };

  async function computeLiveHighestLowest(participantId: string): Promise<LiveHighestLowest> {
    try {
      const flavorProfile = await storage.getFlavorProfile(participantId);
      const journalEntries = await storage.getJournalEntries(participantId);
      const candidates: { name: string; score: number }[] = [];
      for (const rw of flavorProfile.ratedWhiskies) {
        if (rw.rating.overall != null) candidates.push({ name: rw.whisky.name, score: rw.rating.overall });
      }
      for (const j of journalEntries) {
        if (j.personalScore != null) candidates.push({ name: j.name || j.title, score: j.personalScore });
      }
      if (candidates.length === 0) return { highestWhisky: null, lowestWhisky: null };
      let top = candidates[0];
      let bot = candidates[0];
      for (const c of candidates) {
        if (c.score > top.score) top = c;
        if (c.score < bot.score) bot = c;
      }
      return {
        highestWhisky: { name: top.name, score: top.score },
        lowestWhisky: { name: bot.name, score: bot.score },
      };
    } catch {
      return { highestWhisky: null, lowestWhisky: null };
    }
  }

  function mergeLiveHighestLowest<T extends { dataSnapshot?: unknown }>(report: T, live: LiveHighestLowest): T {
    const snap = (report.dataSnapshot && typeof report.dataSnapshot === "object")
      ? (report.dataSnapshot as Record<string, unknown>)
      : {};
    return {
      ...report,
      dataSnapshot: {
        ...snap,
        ...(live.highestWhisky ? { highestWhisky: live.highestWhisky } : {}),
        ...(live.lowestWhisky ? { lowestWhisky: live.lowestWhisky } : {}),
      },
    };
  }

  async function computeLiveWhiskySummaries(participantId: string): Promise<LiveWhiskySummary[]> {
    try {
      const flavorProfile = await storage.getFlavorProfile(participantId);
      const journalEntries = await storage.getJournalEntries(participantId);
      let groupAvgOverall: number | null = null;
      try {
        const allRatings = await storage.getAllRatings();
        const overalls = allRatings.filter(r => r.overall != null).map(r => r.overall!);
        if (overalls.length) groupAvgOverall = Math.round((overalls.reduce((s, v) => s + v, 0) / overalls.length) * 10) / 10;
      } catch {}
      const tastingSummaries = flavorProfile.ratedWhiskies.map(rw => ({
        name: rw.whisky.name,
        distillery: rw.whisky.distillery ?? undefined,
        region: rw.whisky.region ?? undefined,
        scores: { nose: rw.rating.nose, taste: rw.rating.taste, finish: rw.rating.finish, overall: rw.rating.overall },
        flavors: rw.rating.flavors || [],
        vsGroupOverall: rw.rating.overall != null && groupAvgOverall != null ? Math.round((rw.rating.overall - groupAvgOverall) * 10) / 10 : null,
      }));
      const scoredJournalEntries = journalEntries.filter(j =>
        j.personalScore != null || j.noseScore != null || j.tasteScore != null || j.finishScore != null
      );
      const journalSummaries = scoredJournalEntries.map(j => ({
        name: j.name || j.title,
        distillery: j.distillery ?? undefined,
        region: j.region ?? undefined,
        scores: { nose: j.noseScore, taste: j.tasteScore, finish: j.finishScore, overall: j.personalScore },
        flavors: [] as string[],
        vsGroupOverall: j.personalScore != null && groupAvgOverall != null ? Math.round((j.personalScore - groupAvgOverall) * 10) / 10 : null,
      }));
      return [...tastingSummaries, ...journalSummaries]
        .sort((a, b) => (b.scores.overall ?? 0) - (a.scores.overall ?? 0))
        .slice(0, 20);
    } catch {
      return [];
    }
  }

  app.post("/api/participants/:id/connoisseur-report", async (req, res) => {
    try {
      if (await isAIDisabled("connoisseur_report")) return res.status(503).json({ message: "AI feature disabled by admin" });

      const participantId = req.params.id;
      const requesterId = req.headers["x-participant-id"] as string | undefined;
      if (!requesterId || requesterId !== participantId) {
        return res.status(403).json({ message: "Forbidden" });
      }

      const participant = await storage.getParticipant(participantId);
      if (!participant) return res.status(404).json({ message: "Participant not found" });

      const { client: openai, error: aiError, quotaInfo } = await getAIClient(participantId, "connoisseur_report");
      if (!openai) {
        if (aiError === "AI_LIMIT_EXCEEDED") return res.status(429).json({ message: "AI_LIMIT_EXCEEDED", quotaInfo });
        return res.status(503).json({ message: "AI not available" });
      }

      const customPrompt = typeof req.body?.customPrompt === "string" ? req.body.customPrompt.trim().slice(0, 500) : "";
      const tastingId = typeof req.body?.tastingId === "string" ? req.body.tastingId.trim() : undefined;
      const requestedLang = req.body?.language;
      const acceptLang = req.headers["accept-language"] || "";
      const primaryLang = requestedLang === "de" || requestedLang === "en"
        ? requestedLang
        : participant.language === "de" || acceptLang.startsWith("de") ? "de" : "en";

      let tastingContext: { title: string; whiskyNames: string[]; participantRatings: any[] } | null = null;
      if (tastingId) {
        try {
          const tasting = await storage.getTasting(tastingId);
          const whiskies = await storage.getWhiskiesForTasting(tastingId);
          const ratings = await storage.getRatingsForTasting(tastingId);
          const myRatings = ratings.filter(r => r.participantId === participantId);
          tastingContext = {
            title: tasting?.title || "Unknown Tasting",
            whiskyNames: whiskies.map(w => w.name),
            participantRatings: myRatings.map(r => ({
              whiskyName: whiskies.find(w => w.id === r.whiskyId)?.name || "Unknown",
              nose: r.nose, taste: r.taste, finish: r.finish, overall: r.overall,
            })),
          };
        } catch {}
      }

      const flavorProfile = await storage.getFlavorProfile(participantId);
      const stats = await storage.getParticipantStats(participantId);
      const journalEntries = await storage.getJournalEntries(participantId);
      const collection = await storage.getWhiskybaseCollection(participantId);
      const tasteTwins = await storage.getTasteTwins(participantId);

      let communityRankPosition: number | null = null;
      try {
        const communityScores = await storage.getCommunityScores();
        const allParticipantIds = new Set<string>();
        const allRatings = await storage.getAllRatings();
        for (const r of allRatings) allParticipantIds.add(r.participantId);
        communityRankPosition = Array.from(allParticipantIds).indexOf(participantId) + 1;
        if (communityRankPosition === 0) communityRankPosition = null;
      } catch {}

      const topWhiskies = flavorProfile.ratedWhiskies
        .sort((a, b) => (b.rating.overall || 0) - (a.rating.overall || 0))
        .slice(0, 5)
        .map(rw => ({
          name: rw.whisky.name,
          distillery: rw.whisky.distillery,
          region: rw.whisky.region,
          score: rw.rating.overall,
        }));

      const regionBreakdown = Object.entries(flavorProfile.regionBreakdown)
        .sort((a, b) => b[1].count - a[1].count)
        .slice(0, 8)
        .map(([region, data]) => ({ region, count: data.count, avgScore: Math.round(data.avgScore * 10) / 10 }));

      const ageDistribution: Record<string, number> = {};
      for (const item of collection) {
        const age = item.statedAge || "NAS";
        ageDistribution[age] = (ageDistribution[age] || 0) + 1;
      }

      const sortedByScore = [...flavorProfile.ratedWhiskies].sort((a, b) => (b.rating.overall || 0) - (a.rating.overall || 0));
      const highestWhisky = sortedByScore[0] ? { name: sortedByScore[0].whisky.name, score: sortedByScore[0].rating.overall } : null;
      const lowestWhisky = sortedByScore.length > 1 ? { name: sortedByScore[sortedByScore.length - 1].whisky.name, score: sortedByScore[sortedByScore.length - 1].rating.overall } : null;

      let groupAvgOverall: number | null = null;
      let groupAvgScores: { nose: number | null; taste: number | null; finish: number | null; overall: number | null } = { nose: null, taste: null, finish: null, overall: null };
      try {
        const allRatings = await storage.getAllRatings();
        const avg = (vals: number[]) => vals.length > 0 ? Math.round((vals.reduce((s, v) => s + v, 0) / vals.length) * 10) / 10 : null;
        groupAvgScores.nose = avg(allRatings.filter(r => r.nose != null).map(r => r.nose!));
        groupAvgScores.taste = avg(allRatings.filter(r => r.taste != null).map(r => r.taste!));
        groupAvgScores.finish = avg(allRatings.filter(r => r.finish != null).map(r => r.finish!));
        groupAvgScores.overall = avg(allRatings.filter(r => r.overall != null).map(r => r.overall!));
        groupAvgOverall = groupAvgScores.overall;
      } catch {}

      const userAvgOverall = flavorProfile.avgScores?.overall ?? null;
      const vsGroupDelta = userAvgOverall != null && groupAvgOverall != null ? Math.round((userAvgOverall - groupAvgOverall) * 10) / 10 : null;

      const tastingSummaries = flavorProfile.ratedWhiskies.map(rw => ({
        name: rw.whisky.name,
        distillery: rw.whisky.distillery ?? undefined,
        region: rw.whisky.region ?? undefined,
        scores: { nose: rw.rating.nose, taste: rw.rating.taste, finish: rw.rating.finish, overall: rw.rating.overall },
        flavors: rw.rating.flavors || [],
        vsGroupOverall: rw.rating.overall != null && groupAvgOverall != null ? Math.round((rw.rating.overall - groupAvgOverall) * 10) / 10 : null,
      }));

      const scoredJournalEntries = journalEntries.filter(j =>
        j.personalScore != null || j.noseScore != null || j.tasteScore != null || j.finishScore != null
      );
      const journalSummaries = scoredJournalEntries.map(j => ({
        name: j.name || j.title,
        distillery: j.distillery ?? undefined,
        region: j.region ?? undefined,
        scores: { nose: j.noseScore, taste: j.tasteScore, finish: j.finishScore, overall: j.personalScore },
        flavors: [] as string[],
        vsGroupOverall: j.personalScore != null && groupAvgOverall != null ? Math.round((j.personalScore - groupAvgOverall) * 10) / 10 : null,
      }));

      const whiskySummaries = [...tastingSummaries, ...journalSummaries]
        .sort((a, b) => (b.scores.overall ?? 0) - (a.scores.overall ?? 0))
        .slice(0, 20);

      const totalRatingsCount = stats.totalRatings + scoredJournalEntries.length;

      const dataSnapshot = {
        totalRatings: totalRatingsCount,
        totalTastings: stats.totalTastings,
        totalJournalEntries: stats.totalJournalEntries,
        collectionSize: collection.length,
        avgScores: flavorProfile.avgScores,
        groupAvgOverall,
        groupAvgScores,
        vsGroupDelta,
        highestWhisky,
        lowestWhisky,
        whiskySummaries,
        regionBreakdown,
        topRegion: regionBreakdown[0]?.region || null,
        topRegionCount: regionBreakdown[0]?.count || 0,
        smokeAffinityIndex: participant.smokeAffinityIndex,
        sweetnessBias: participant.sweetnessBias,
        ratingStabilityScore: stats.ratingStabilityScore,
        explorationIndex: stats.explorationIndex,
        tasteTwinsCount: tasteTwins.length,
        topTasteTwin: tasteTwins[0]?.participantName || null,
        topTasteTwinCorrelation: tasteTwins[0]?.correlation || null,
      };

      const profileData = {
        name: participant.name,
        totalRatings: stats.totalRatings,
        totalTastings: stats.totalTastings,
        totalJournalEntries: stats.totalJournalEntries,
        avgScores: flavorProfile.avgScores,
        topWhiskies,
        regionBreakdown,
        caskBreakdown: Object.entries(flavorProfile.caskBreakdown)
          .sort((a, b) => b[1].count - a[1].count)
          .slice(0, 5)
          .map(([cask, data]) => ({ cask, count: data.count, avgScore: Math.round(data.avgScore * 10) / 10 })),
        peatBreakdown: Object.entries(flavorProfile.peatBreakdown)
          .sort((a, b) => b[1].count - a[1].count)
          .map(([level, data]) => ({ level, count: data.count, avgScore: Math.round(data.avgScore * 10) / 10 })),
        collectionSize: collection.length,
        collectionRegions: Object.keys(ageDistribution).length,
        journalCount: journalEntries.length,
        recentJournals: journalEntries.slice(0, 3).map(j => ({ title: j.title, whisky: j.name, score: j.personalScore })),
        smokeAffinityIndex: participant.smokeAffinityIndex,
        sweetnessBias: participant.sweetnessBias,
        ratingStabilityScore: stats.ratingStabilityScore,
        explorationIndex: stats.explorationIndex,
        tasteTwins: tasteTwins.slice(0, 3).map(t => ({ name: t.participantName, correlation: t.correlation, sharedWhiskies: t.sharedWhiskies })),
        communityRankPosition,
      };

      const response = await openai.chat.completions.create({
        model: "gpt-4o",
        messages: [
          {
            role: "system",
            content: `You are a master blender creating a personal Connoisseur Report for a whisky enthusiast. This is a structured, intimate analysis of their whisky journey.

Return a JSON object with exactly these fields:

- "palateProfile_en": Section 1 — Palate Profile (80-120 words, English). A warm, personal analysis of their taste preferences. Reference their strongest scoring dimension (nose/taste/finish), regional tendencies, and what makes their palate unique. Address by first name. Flowing prose, no markdown.
- "palateProfile_de": Same section in natural German.

- "tastingHighlights_en": Section 2 — Tasting Highlights (80-120 words, English). Discuss their top-rated and lowest-rated whiskies with specific names and scores. Note patterns — do they prefer peated, sherried, or bourbon-cask? Reference cask or region trends from the data. Flowing prose, no markdown.
- "tastingHighlights_de": Same section in natural German.

- "recommendation_en": Section 3 — Recommendation & Outlook (60-100 words, English). Based on their profile, suggest a whisky style, region, or specific expression they should explore next. End with an encouraging reflection on their journey. Flowing prose, no markdown.
- "recommendation_de": Same section in natural German.

- "quote_en": A single poetic sentence (max 15 words, English) that captures their whisky personality — suitable for sharing.
- "quote_de": Same quote in natural German.

- "summary_en": A concise one-sentence summary (max 25 words, English) of their overall whisky profile.
- "summary_de": Same summary in natural German.

Write as if you know this person through their tasting notes. Tone: warm, knowledgeable, personal — mentor to a fellow enthusiast.`
          },
          {
            role: "user",
            content: `Write a Palate Letter for this whisky enthusiast:\n\n${JSON.stringify(profileData, null, 2)}${tastingContext ? `\n\nThis report was triggered after the tasting "${tastingContext.title}". The participant rated these whiskies in this tasting:\n${JSON.stringify(tastingContext.participantRatings, null, 2)}\n\nPlease reference this specific tasting in the letter.` : ""}${customPrompt ? `\n\nAdditional focus from the user: ${customPrompt}` : ""}`
          }
        ],
        max_tokens: 2000,
        temperature: 0.8,
        response_format: { type: "json_object" },
      });

      const content = response.choices[0]?.message?.content || "{}";
      let parsed: Record<string, string>;
      try { parsed = JSON.parse(content); } catch { parsed = { palateProfile_en: content }; }

      const palateProfileEn = parsed.palateProfile_en || parsed.report_en || parsed.report || content;
      const palateProfileDe = parsed.palateProfile_de || parsed.report_de || palateProfileEn;
      const tastingHighlightsEn = parsed.tastingHighlights_en || "";
      const tastingHighlightsDe = parsed.tastingHighlights_de || "";
      const recommendationEn = parsed.recommendation_en || "";
      const recommendationDe = parsed.recommendation_de || "";
      const quoteEn = parsed.quote_en || "";
      const quoteDe = parsed.quote_de || "";
      const summaryEn = parsed.summary_en || parsed.summary || "";
      const summaryDe = parsed.summary_de || summaryEn;

      const reportEn = [palateProfileEn, tastingHighlightsEn, recommendationEn].filter(Boolean).join("\n\n");
      const reportDe = [palateProfileDe, tastingHighlightsDe, recommendationDe].filter(Boolean).join("\n\n");
      const reportContent = primaryLang === "de" ? reportDe : reportEn;
      const summary = primaryLang === "de" ? summaryDe : summaryEn;

      const enrichedSnapshot = {
        ...dataSnapshot,
        reportEn,
        reportDe,
        summaryEn,
        summaryDe,
        palateProfileEn,
        palateProfileDe,
        tastingHighlightsEn,
        tastingHighlightsDe,
        recommendationEn,
        recommendationDe,
        quoteEn,
        quoteDe,
        ...(tastingId ? { tastingId } : {}),
      };

      const report = await storage.createConnoisseurReport({
        participantId,
        reportContent,
        summary,
        dataSnapshot: enrichedSnapshot,
        language: primaryLang,
      });

      res.status(201).json(report);
    } catch (e: any) {
      console.error("Connoisseur report error:", e.message);
      res.status(500).json({ message: "Could not generate connoisseur report" });
    }
  });

  app.get("/api/participants/:id/connoisseur-reports", async (req, res) => {
    try {
      const participantId = req.params.id;
      const requesterId = req.headers["x-participant-id"] as string | undefined;
      if (!requesterId || requesterId !== participantId) {
        const requester = requesterId ? await storage.getParticipant(requesterId) : null;
        if (!requester || requester.role !== "admin") {
          return res.status(403).json({ message: "Forbidden" });
        }
      }

      const reports = await storage.getConnoisseurReports(participantId);
      let liveSummaries: LiveWhiskySummary[] | null = null;
      const liveHL = await computeLiveHighestLowest(participantId);
      const enriched = await Promise.all(reports.map(async (r) => {
        const existing = extractSnapshotWhiskySummaries(r.dataSnapshot);
        let summaries: LiveWhiskySummary[];
        if (existing.length > 0) {
          summaries = existing;
        } else {
          if (liveSummaries === null) liveSummaries = await computeLiveWhiskySummaries(participantId);
          summaries = liveSummaries;
        }
        return mergeLiveHighestLowest({ ...r, liveWhiskySummaries: summaries }, liveHL);
      }));
      res.json(enriched);
    } catch (e: any) {
      res.status(500).json({ message: e.message });
    }
  });

  // --- Whisky-DNA Aroma-Radar (on-the-fly, no persistence) ---
  const WHISKY_DNA_CATEGORIES: Array<{ id: string; en: string; de: string; color: string; keywords: string[] }> = [
    { id: "fruity", en: "Fruity", de: "Fruchtig", color: "#E07B4C", keywords: ["apple","apfel","pear","birne","citrus","zitrus","lemon","zitrone","orange","lime","grapefruit","berry","beere","strawberry","raspberry","blackberry","blueberry","tropical","mango","pineapple","ananas","banana","banane","passion fruit","raisin","date","fig","feige","prune","sultana","trockenfrucht","frucht","fruit","apricot","aprikose","peach","pfirsich","cherry","kirsche","plum","pflaume"] },
    { id: "floral", en: "Floral", de: "Blumig", color: "#C77DBA", keywords: ["rose","lavender","lavendel","heather","heidekraut","elderflower","holunder","jasmine","jasmin","blossom","blüte","floral","blumig","violet","veilchen"] },
    { id: "sweet", en: "Sweet", de: "Süß", color: "#D4A853", keywords: ["honey","honig","vanilla","vanille","caramel","karamell","butterscotch","toffee","fudge","chocolate","schokolade","cocoa","kakao","marzipan","brown sugar","brauner zucker","molasses","melasse","treacle","sugar","zucker","sweet","süß","syrup","sirup","maple"] },
    { id: "creamy", en: "Creamy", de: "Cremig", color: "#D4B896", keywords: ["butter","buttery","buttrig","cream","sahne","creamy","cremig","custard","pudding","crème","milk","milch","yoghurt","joghurt","yogurt","vanilla pudding","mascarpone"] },
    { id: "malty", en: "Malty", de: "Malzig", color: "#B8934A", keywords: ["cereal","getreide","grain","barley","gerste","malt","malz","malty","malzig","biscuit","keks","cookie","shortbread","bread","brot","dough","teig","toast","toasted","geröstet","oatmeal","haferflocken","oat","hafer","porridge"] },
    { id: "herbal", en: "Herbal", de: "Kräuter", color: "#6B8E5A", keywords: ["mint","minze","menthol","eucalyptus","eukalyptus","grass","gras","hay","heu","tea","tee","green tea","thyme","thymian","rosemary","rosmarin","herbal","kräuter","kräutrig","sage","salbei","basil","basilikum"] },
    { id: "nutty", en: "Nutty", de: "Nussig", color: "#9B7653", keywords: ["walnut","walnuss","hazelnut","haselnuss","coconut","kokos","kokosnuss","almond","mandel","pecan","pekannuss","nutty","nussig","nuss","nut"] },
    { id: "woody", en: "Woody", de: "Holzig", color: "#8B6F47", keywords: ["oak","eiche","eichenholz","cedar","zeder","sandalwood","sandelholz","pine","kiefer","resin","harz","sawdust","sägemehl","wood","holz","woody","holzig","balsamic","balsamisch"] },
    { id: "spicy", en: "Spicy", de: "Würzig", color: "#C04E3E", keywords: ["cinnamon","zimt","pepper","pfeffer","ginger","ingwer","clove","nelke","gewürznelke","nutmeg","muskat","muskatnuss","anise","anis","liquorice","licorice","lakritz","spicy","würzig","spice","gewürz","cardamom","kardamom","chili","chilli"] },
    { id: "earthy", en: "Earthy", de: "Erdig", color: "#7A6855", keywords: ["leather","leder","tobacco","tabak","cigar","zigarre","mushroom","pilz","truffle","trüffel","moss","moos","forest floor","waldboden","soil","erde","earth","loam","earthy","erdig","humus"] },
    { id: "smoky", en: "Smoky", de: "Rauchig", color: "#6B7280", keywords: ["peat","torf","peaty","torfig","campfire","lagerfeuer","bonfire","smoke","rauch","smoky","rauchig","charcoal","holzkohle","ash","asche","tar","teer","bbq","grill","smoked","geräuchert","bacon","speck"] },
    { id: "maritime", en: "Maritime", de: "Maritim", color: "#4A90A4", keywords: ["sea salt","meersalz","salt","salz","salty","salzig","brine","salzlake","briny","iodine","jod","medicinal","medizinisch","seaweed","seetang","kelp","algae","alge","oyster","auster","shellfish","maritime","maritim","ocean","meer","sea","see"] },
  ];

  // ---------- Whisky-DNA preference helpers ----------
  // Per-dram preference score 0..100 (personalScore -> overallScore -> mean of nose/taste/finish)
  const dramPrefScore = (e: any): number | null => {
    if (typeof e?.personalScore === "number") return e.personalScore;
    if (typeof e?.overallScore === "number") return e.overallScore;
    const parts = [e?.noseScore, e?.tasteScore, e?.finishScore].filter((v) => typeof v === "number") as number[];
    if (parts.length === 0) return null;
    return parts.reduce((a, b) => a + b, 0) / parts.length;
  };

  const parseAge = (s: string | null | undefined): number | null => {
    if (!s) return null;
    const m = String(s).match(/(\d{1,3})/);
    if (!m) return null;
    const v = parseInt(m[1], 10);
    return Number.isFinite(v) && v > 0 && v < 100 ? v : null;
  };

  const ageBand = (s: string | null | undefined): { id: string; en: string; de: string } | null => {
    const a = parseAge(s);
    if (a == null) {
      const txt = (s || "").toString().toLowerCase();
      if (/nas|no age/.test(txt)) return { id: "nas", en: "NAS", de: "Ohne Altersangabe" };
      return null;
    }
    if (a < 10) return { id: "young", en: "Young (3–9 yrs)", de: "Jung (3–9 J.)" };
    if (a < 18) return { id: "classic", en: "Classic (10–17 yrs)", de: "Klassisch (10–17 J.)" };
    if (a < 26) return { id: "mature", en: "Mature (18–25 yrs)", de: "Reif (18–25 J.)" };
    return { id: "old", en: "Old (25+ yrs)", de: "Alt (25+ J.)" };
  };

  const abvBand = (v: number | null | undefined): { id: string; en: string; de: string } | null => {
    if (typeof v !== "number" || !Number.isFinite(v) || v <= 0) return null;
    if (v < 40) return { id: "low", en: "Low (<40%)", de: "Niedrig (<40%)" };
    if (v < 46) return { id: "standard", en: "Standard (40–46%)", de: "Standard (40–46%)" };
    if (v < 50) return { id: "highish", en: "Higher strength (46–50%)", de: "Höhere Stärke (46–50%)" };
    if (v < 55) return { id: "high", en: "High strength (50–55%)", de: "Hohe Stärke (50–55%)" };
    return { id: "cask", en: "Cask strength (55%+)", de: "Fassstärke (55%+)" };
  };

  // Map a centred-z value to 0..100 affinity for radar display.
  // 50 = neutral, +2σ ≈ 100, −2σ ≈ 0.
  const zToAffinity = (z: number) => Math.max(0, Math.min(100, 50 + 25 * z));

  app.get("/api/participants/:id/whisky-dna", async (req, res) => {
    try {
      const participantId = req.params.id;
      const requesterId = req.headers["x-participant-id"] as string | undefined;
      if (!requesterId || requesterId !== participantId) {
        const requester = requesterId ? await storage.getParticipant(requesterId) : null;
        if (!requester || requester.role !== "admin") {
          return res.status(403).json({ message: "Forbidden" });
        }
      }

      const { version: versionAtStart, data: cached } = getCachedWhiskyDna(participantId);
      if (cached !== undefined) {
        return res.json(cached);
      }

      const allEntries = await storage.getJournalEntries(participantId);
      const hasOverallScore = (e: unknown): e is { overallScore: number | null } =>
        typeof e === "object" && e !== null && "overallScore" in e;
      // Frequency pool: every non-DB entry that has *any* note or score —
      // identical inclusion rule as before, so the legacy "Top aromas" stays comparable.
      const entries = allEntries.filter((e) => {
        if (e.source === "casksense-database") return false;
        const overallScore = hasOverallScore(e) ? e.overallScore : null;
        return (
          e.noseScore != null ||
          e.tasteScore != null ||
          e.finishScore != null ||
          overallScore != null ||
          e.personalScore != null
        );
      });

      const n = entries.length;

      // Affinity pool: entries that yield a usable preference score (0..100).
      const ratedEntries = entries
        .map((e) => ({ entry: e, score: dramPrefScore(e) }))
        .filter((x): x is { entry: any; score: number } => typeof x.score === "number");
      const ratedScores = ratedEntries.map((x) => x.score);
      const nRated = ratedScores.length;
      const baselineMean = nRated > 0 ? ratedScores.reduce((a, b) => a + b, 0) / nRated : 0;
      const baselineVar =
        nRated > 1
          ? ratedScores.reduce((a, b) => a + (b - baselineMean) * (b - baselineMean), 0) / (nRated - 1)
          : 0;
      const baselineStd = Math.sqrt(baselineVar);
      // Avoid division by zero: when stddev is 0 use centred raw delta with a soft scale of 10.
      const stdForZ = baselineStd > 0 ? baselineStd : 10;

      const ratedWithStats = ratedEntries.map(({ entry, score }) => {
        const centered = score - baselineMean;
        const z = centered / stdForZ;
        const text = [entry.noseNotes, entry.tasteNotes, entry.finishNotes].filter(Boolean).join(" ").toLowerCase();
        return { entry, score, centered, z, text };
      });

      // Texts for the legacy frequency view (uses ALL entries in the DNA pool).
      const entryTexts = entries.map((e) =>
        [e.noseNotes, e.tasteNotes, e.finishNotes].filter(Boolean).join(" ").toLowerCase()
      );

      const escapeRe = (s: string) => s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
      const keywordRegexes = WHISKY_DNA_CATEGORIES.map((cat) => ({
        cat,
        regexes: cat.keywords.map(
          (k) => new RegExp(`(?<![\\p{L}\\p{N}_])${escapeRe(k)}(?![\\p{L}\\p{N}_])`, "iu"),
        ),
      }));

      const keywordCounts: Record<string, number> = {};

      const MIN_AXIS_SAMPLE = 3;

      const categories = keywordRegexes.map(({ cat, regexes }) => {
        // Frequency (legacy) — drams with at least one keyword match
        let freqCount = 0;
        for (let i = 0; i < entryTexts.length; i++) {
          const text = entryTexts[i];
          if (!text) continue;
          let matchedInEntry = false;
          for (let k = 0; k < cat.keywords.length; k++) {
            const kw = cat.keywords[k];
            const re = regexes[k];
            if (re.test(text)) {
              keywordCounts[kw] = (keywordCounts[kw] || 0) + 1;
              if (!matchedInEntry) matchedInEntry = true;
            }
          }
          if (matchedInEntry) freqCount++;
        }
        const freqPct = n > 0 ? freqCount / n : 0;

        // Affinity — average centred-z over rated drams whose notes mention this aroma.
        const matched = ratedWithStats.filter((r) => r.text && regexes.some((re) => re.test(r.text)));
        const sample = matched.length;
        const meanZ = sample > 0 ? matched.reduce((a, r) => a + r.z, 0) / sample : 0;
        const meanCentered = sample > 0 ? matched.reduce((a, r) => a + r.centered, 0) / sample : 0;
        const sufficient = sample >= MIN_AXIS_SAMPLE;
        // Damped affinity for low-sample axes — pull toward neutral 50.
        const rawAff = zToAffinity(meanZ);
        const affinity = sufficient ? rawAff : 50 + (rawAff - 50) * (sample / MIN_AXIS_SAMPLE);
        const pct = affinity / 100;
        // CI half-width derived from THIS axis' sample, not the global pool.
        const ciHalfAxis = sample > 0 ? Math.min(0.42, 0.42 / Math.sqrt(sample)) : 0.42;
        const lower = Math.max(0, Math.min(1, pct - ciHalfAxis));
        const upper = Math.max(0, Math.min(1, pct + ciHalfAxis));
        return {
          id: cat.id,
          en: cat.en,
          de: cat.de,
          color: cat.color,
          // Legacy field — now backed by affinity so the radar shows preference.
          count: freqCount,
          pct,
          lower,
          upper,
          // New, explicit fields
          affinity: Math.round(affinity * 10) / 10,
          meanCentered: Math.round(meanCentered * 10) / 10,
          sample,
          sufficient,
          frequency: { count: freqCount, pct: freqPct },
        };
      });

      const ciHalf = n > 0 ? Math.min(0.42, 0.42 / Math.sqrt(n)) : 0.42;
      const stability = Math.round(100 * (1 - Math.exp(-nRated / 25)));

      let phase: "unknown" | "emerging" | "stable" | "crystal";
      if (nRated < 10) phase = "unknown";
      else if (nRated < 30) phase = "emerging";
      else if (nRated < 60) phase = "stable";
      else phase = "crystal";

      const nForCI10 = Math.max(0, Math.ceil(Math.pow(0.42 / 0.10, 2)) - nRated);

      const topKeywords = Object.entries(keywordCounts)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 8)
        .map(([keyword, count]) => ({ keyword, count }));

      const sortedByAff = [...categories].sort((a, b) => b.affinity - a.affinity);
      const dominantCategory = sortedByAff.find((c) => c.sufficient && c.affinity > 50)?.id ?? null;
      const sortedAsc = [...categories]
        .filter((c) => c.sufficient)
        .sort((a, b) => a.affinity - b.affinity);
      const rareCategory = sortedAsc.length ? sortedAsc[0].id : null;

      // ---------- Structural preferences ----------
      type Bucket = { id: string; label: { en: string; de: string }; sample: number; sumZ: number; sumCentered: number };
      const dimensions: Record<
        string,
        { buckets: Map<string, Bucket>; minSample: number }
      > = {
        region: { buckets: new Map(), minSample: 2 },
        caskType: { buckets: new Map(), minSample: 2 },
        peatLevel: { buckets: new Map(), minSample: 2 },
        ageBand: { buckets: new Map(), minSample: 2 },
        abvBand: { buckets: new Map(), minSample: 2 },
        distillery: { buckets: new Map(), minSample: 2 },
      };

      const addBucket = (
        dim: string,
        id: string | null,
        labelEn: string,
        labelDe: string,
        z: number,
        centered: number,
      ) => {
        if (!id) return;
        const map = dimensions[dim].buckets;
        const b = map.get(id) ?? { id, label: { en: labelEn, de: labelDe }, sample: 0, sumZ: 0, sumCentered: 0 };
        b.sample += 1;
        b.sumZ += z;
        b.sumCentered += centered;
        map.set(id, b);
      };

      for (const r of ratedWithStats) {
        const e: any = r.entry;
        if (e.region) addBucket("region", String(e.region).trim() || null, String(e.region).trim(), String(e.region).trim(), r.z, r.centered);
        if (e.caskType) addBucket("caskType", String(e.caskType).trim() || null, String(e.caskType).trim(), String(e.caskType).trim(), r.z, r.centered);
        if (e.peatLevel) addBucket("peatLevel", String(e.peatLevel).trim() || null, String(e.peatLevel).trim(), String(e.peatLevel).trim(), r.z, r.centered);
        const ab = ageBand(e.age);
        if (ab) addBucket("ageBand", ab.id, ab.en, ab.de, r.z, r.centered);
        const vb = abvBand(typeof e.abv === "number" ? e.abv : null);
        if (vb) addBucket("abvBand", vb.id, vb.en, vb.de, r.z, r.centered);
        if (e.distillery) addBucket("distillery", String(e.distillery).trim() || null, String(e.distillery).trim(), String(e.distillery).trim(), r.z, r.centered);
      }

      const buildTop = (dim: string, limit: number) => {
        const cfg = dimensions[dim];
        const arr = Array.from(cfg.buckets.values()).map((b) => {
          const meanZ = b.sample > 0 ? b.sumZ / b.sample : 0;
          const meanCentered = b.sample > 0 ? b.sumCentered / b.sample : 0;
          const affinity = zToAffinity(meanZ);
          return {
            id: b.id,
            label: b.label,
            sample: b.sample,
            affinity: Math.round(affinity * 10) / 10,
            meanCentered: Math.round(meanCentered * 10) / 10,
          };
        });
        return arr
          .filter((x) => x.sample >= cfg.minSample && x.affinity > 50)
          .sort((a, b) => b.affinity - a.affinity)
          .slice(0, limit);
      };

      const structural = {
        region: buildTop("region", 5),
        caskType: buildTop("caskType", 5),
        peatLevel: buildTop("peatLevel", 4),
        ageBand: buildTop("ageBand", 4),
        abvBand: buildTop("abvBand", 4),
        distillery: buildTop("distillery", 5),
      };

      const payload = {
        n,
        stability,
        ciHalf,
        nForCI10,
        phase,
        categories,
        topKeywords,
        dominantCategory,
        rareCategory,
        // New affinity-model fields
        baseline: {
          n: nRated,
          mean: Math.round(baselineMean * 10) / 10,
          stddev: Math.round(baselineStd * 10) / 10,
        },
        affinity: categories.map((c) => ({
          id: c.id,
          en: c.en,
          de: c.de,
          color: c.color,
          affinity: c.affinity,
          sample: c.sample,
          meanCentered: c.meanCentered,
          sufficient: c.sufficient,
          ciLower: c.lower,
          ciUpper: c.upper,
        })),
        samplePerAxis: Object.fromEntries(categories.map((c) => [c.id, c.sample])),
        structural,
      };
      setCachedWhiskyDna(participantId, versionAtStart, payload);
      res.json(payload);
    } catch (e: any) {
      console.error("Whisky-DNA error:", e?.message || e);
      res.status(500).json({ message: e?.message || "Failed to compute Whisky-DNA" });
    }
  });

  // --- Whisky-DNA "Try next" recommendations (whiskies that strengthen weak axes) ---
  app.get("/api/participants/:id/whisky-dna/recommendations", async (req, res) => {
    try {
      const participantId = req.params.id;
      const requesterId = req.headers["x-participant-id"] as string | undefined;
      if (!requesterId || requesterId !== participantId) {
        const requester = requesterId ? await storage.getParticipant(requesterId) : null;
        if (!requester || requester.role !== "admin") {
          return res.status(403).json({ message: "Forbidden" });
        }
      }

      const escapeRe = (s: string) => s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
      const keywordRegexes = WHISKY_DNA_CATEGORIES.map((cat) => ({
        cat,
        regexes: cat.keywords.map(
          (k) => new RegExp(`(?<![\\p{L}\\p{N}_])${escapeRe(k)}(?![\\p{L}\\p{N}_])`, "iu"),
        ),
      }));

      // 1) Compute the user's per-axis affinity from rated journal entries.
      const allEntries = await storage.getJournalEntries(participantId);
      const hasOverallScore = (e: unknown): e is { overallScore: number | null } =>
        typeof e === "object" && e !== null && "overallScore" in e;
      const userEntries = allEntries.filter((e) => {
        if (e.source === "casksense-database") return false;
        const overallScore = hasOverallScore(e) ? e.overallScore : null;
        return (
          e.noseScore != null ||
          e.tasteScore != null ||
          e.finishScore != null ||
          overallScore != null ||
          e.personalScore != null
        );
      });

      const ratedEntries = userEntries
        .map((e) => ({ entry: e as any, score: dramPrefScore(e) }))
        .filter((x): x is { entry: any; score: number } => typeof x.score === "number");
      const ratedScores = ratedEntries.map((x) => x.score);
      const baselineMean = ratedScores.length > 0 ? ratedScores.reduce((a, b) => a + b, 0) / ratedScores.length : 0;
      const baselineVar =
        ratedScores.length > 1
          ? ratedScores.reduce((a, b) => a + (b - baselineMean) * (b - baselineMean), 0) / (ratedScores.length - 1)
          : 0;
      const baselineStd = Math.sqrt(baselineVar);
      const stdForZ = baselineStd > 0 ? baselineStd : 10;

      const ratedWithStats = ratedEntries.map(({ entry, score }) => {
        const z = (score - baselineMean) / stdForZ;
        const text = [entry.noseNotes, entry.tasteNotes, entry.finishNotes].filter(Boolean).join(" ").toLowerCase();
        return { entry, score, z, text };
      });

      const MIN_AXIS_SAMPLE = 3;
      const userAffinity: Record<string, { affinity: number; sample: number; sufficient: boolean }> = {};
      for (const { cat, regexes } of keywordRegexes) {
        const matched = ratedWithStats.filter((r) => r.text && regexes.some((re) => re.test(r.text)));
        const sample = matched.length;
        const meanZ = sample > 0 ? matched.reduce((a, r) => a + r.z, 0) / sample : 0;
        const sufficient = sample >= MIN_AXIS_SAMPLE;
        const rawAff = zToAffinity(meanZ);
        const affinity = sufficient ? rawAff : 50 + (rawAff - 50) * (sample / MIN_AXIS_SAMPLE);
        userAffinity[cat.id] = { affinity, sample, sufficient };
      }

      // 2) Positive-affinity axes (favourites) — at least one with sufficient sample, else fall back
      // to the strongest axes overall so we still produce useful suggestions.
      const positiveCats = WHISKY_DNA_CATEGORIES
        .filter((c) => userAffinity[c.id].sufficient && userAffinity[c.id].affinity > 55)
        .sort((a, b) => userAffinity[b.id].affinity - userAffinity[a.id].affinity);
      const fallbackCats = [...WHISKY_DNA_CATEGORIES].sort(
        (a, b) => userAffinity[b.id].affinity - userAffinity[a.id].affinity,
      );
      const targetCats = (positiveCats.length > 0 ? positiveCats : fallbackCats).slice(0, 4);
      const targetIds = new Set(targetCats.map((c) => c.id));

      // 3) Aggregate structural preferences from rated entries.
      const accumulate = (key: (e: any) => string | null) => {
        const map = new Map<string, { sumZ: number; sample: number }>();
        for (const r of ratedWithStats) {
          const k = key(r.entry);
          if (!k) continue;
          const b = map.get(k) ?? { sumZ: 0, sample: 0 };
          b.sumZ += r.z;
          b.sample += 1;
          map.set(k, b);
        }
        const out = new Map<string, number>(); // key -> affinity 0..100
        map.forEach((v, k) => {
          if (v.sample < 2) return;
          const aff = zToAffinity(v.sumZ / v.sample);
          if (aff > 55) out.set(k, aff);
        });
        return out;
      };
      const norm = (s: string | null | undefined) => (s || "").trim().toLowerCase();
      const preferredRegions = accumulate((e) => (e.region ? norm(e.region) : null));
      const preferredCasks = accumulate((e) => (e.caskType ? norm(e.caskType) : null));
      const preferredPeat = accumulate((e) => (e.peatLevel ? norm(e.peatLevel) : null));
      const preferredAge = accumulate((e) => ageBand(e.age)?.id ?? null);
      const preferredAbv = accumulate((e) => abvBand(typeof e.abv === "number" ? e.abv : null)?.id ?? null);

      // 4) Build a tasted-set of (distillery|name) keys to encourage exploration
      const tastedKeys = new Set<string>();
      for (const e of allEntries) {
        const key = `${norm(e.distillery)}|${norm(e.name || e.title)}`;
        if (key !== "|") tastedKeys.add(key);
      }

      // 5) Score candidates from whiskies + benchmark entries
      type Candidate = {
        key: string;
        name: string;
        distillery: string | null;
        region: string | null;
        category: string | null;
        imageUrl: string | null;
        source: "whisky" | "benchmark";
        matched: Record<string, number>;
        structuralBonus: number;
        score: number;
      };

      const scoreText = (text: string): { matched: Record<string, number>; score: number } => {
        const lower = text.toLowerCase();
        const matched: Record<string, number> = {};
        let score = 0;
        for (const { cat, regexes } of keywordRegexes) {
          if (!targetIds.has(cat.id)) continue;
          let hits = 0;
          for (const re of regexes) {
            if (re.test(lower)) hits++;
          }
          if (hits > 0) {
            matched[cat.id] = hits;
            // Weight aroma hits by the user's affinity for that axis.
            const w = (userAffinity[cat.id]?.affinity ?? 50) / 50; // ~0..2
            score += hits * w;
          }
        }
        return { matched, score };
      };

      const structuralBonusFor = (
        region: string | null,
        cask: string | null,
        peat: string | null,
        age: string | null,
        abv: number | null,
      ) => {
        let bonus = 0;
        if (region && preferredRegions.has(norm(region))) bonus += (preferredRegions.get(norm(region))! - 50) / 25;
        if (cask && preferredCasks.has(norm(cask))) bonus += (preferredCasks.get(norm(cask))! - 50) / 25;
        if (peat && preferredPeat.has(norm(peat))) bonus += (preferredPeat.get(norm(peat))! - 50) / 25;
        const ab = ageBand(age);
        if (ab && preferredAge.has(ab.id)) bonus += (preferredAge.get(ab.id)! - 50) / 25;
        const vb = abvBand(typeof abv === "number" ? abv : null);
        if (vb && preferredAbv.has(vb.id)) bonus += (preferredAbv.get(vb.id)! - 50) / 25;
        return bonus;
      };

      const candidates: Candidate[] = [];

      const whiskies = await storage.getAllWhiskies();
      for (const w of whiskies) {
        const text = [w.notes, w.hostNotes, w.hostSummary].filter(Boolean).join(" ");
        if (!text.trim()) continue;
        const { matched, score } = scoreText(text);
        if (score < 2 || Object.keys(matched).length === 0) continue;
        const key = `${norm(w.distillery)}|${norm(w.name)}`;
        if (tastedKeys.has(key)) continue;
        const structuralBonus = structuralBonusFor(w.region, w.caskType, w.peatLevel, (w as any).age ?? null, typeof (w as any).abv === "number" ? (w as any).abv : null);
        candidates.push({
          key,
          name: w.name,
          distillery: w.distillery,
          region: w.region,
          category: w.category,
          imageUrl: w.imageUrl,
          source: "whisky",
          matched,
          structuralBonus,
          score: score + structuralBonus,
        });
      }

      const benchmarks = await storage.getBenchmarkEntries();
      for (const b of benchmarks) {
        const text = [b.noseNotes, b.tasteNotes, b.finishNotes, b.overallNotes].filter(Boolean).join(" ");
        if (!text.trim()) continue;
        const { matched, score } = scoreText(text);
        if (score < 2 || Object.keys(matched).length === 0) continue;
        const key = `${norm(b.distillery)}|${norm(b.name)}`;
        if (tastedKeys.has(key)) continue;
        const structuralBonus = structuralBonusFor(b.region, b.caskType ?? null, null, (b as any).age ?? null, typeof (b as any).abv === "number" ? (b as any).abv : null);
        candidates.push({
          key,
          name: b.name,
          distillery: b.distillery,
          region: b.region,
          category: b.category,
          imageUrl: null,
          source: "benchmark",
          matched,
          structuralBonus,
          score: score + structuralBonus,
        });
      }

      // 6) De-duplicate by (distillery|name), keeping the highest-scoring entry
      const byKey = new Map<string, Candidate>();
      for (const c of candidates) {
        const existing = byKey.get(c.key);
        if (!existing || c.score > existing.score) byKey.set(c.key, c);
      }

      // 7) Sort: prefer candidates that hit MORE distinct preferred categories first, then total score
      const ranked = Array.from(byKey.values()).sort((a, b) => {
        const da = Object.keys(a.matched).length;
        const db = Object.keys(b.matched).length;
        if (db !== da) return db - da;
        return b.score - a.score;
      });

      const recommendations = ranked.slice(0, 5).map((c) => ({
        name: c.name,
        distillery: c.distillery,
        region: c.region,
        category: c.category,
        imageUrl: c.imageUrl,
        source: c.source,
        matchedCategories: Object.keys(c.matched).map((id) => {
          const cat = WHISKY_DNA_CATEGORIES.find((x) => x.id === id)!;
          return { id, en: cat.en, de: cat.de, color: cat.color, hits: c.matched[id] };
        }),
        score: Math.round(c.score * 10) / 10,
      }));

      res.json({
        // Field name kept for backward-compatibility with the frontend, but the meaning is
        // now "axes we are recommending for" (the user's positive-affinity axes), not weak ones.
        weakCategories: targetCats.map((c) => ({
          id: c.id,
          en: c.en,
          de: c.de,
          color: c.color,
          pct: (userAffinity[c.id]?.affinity ?? 50) / 100,
        })),
        recommendations,
      });
    } catch (e: any) {
      console.error("Whisky-DNA recommendations error:", e?.message || e);
      res.status(500).json({ message: e?.message || "Failed to compute recommendations" });
    }
  });

  app.get("/api/participants/:id/connoisseur-reports/:reportId", async (req, res) => {
    try {
      const participantId = req.params.id;
      const requesterId = req.headers["x-participant-id"] as string | undefined;
      if (!requesterId || requesterId !== participantId) {
        const requester = requesterId ? await storage.getParticipant(requesterId) : null;
        if (!requester || requester.role !== "admin") {
          return res.status(403).json({ message: "Forbidden" });
        }
      }

      const report = await storage.getConnoisseurReport(req.params.reportId);
      if (!report || report.participantId !== participantId) {
        return res.status(404).json({ message: "Report not found" });
      }
      const existing = extractSnapshotWhiskySummaries(report.dataSnapshot);
      const liveWhiskySummaries = existing.length > 0
        ? existing
        : await computeLiveWhiskySummaries(participantId);
      const liveHL = await computeLiveHighestLowest(participantId);
      res.json(mergeLiveHighestLowest({ ...report, liveWhiskySummaries }, liveHL));
    } catch (e: any) {
      res.status(500).json({ message: e.message });
    }
  });

