  // --- Whiskybase Lookup (auto-fill from WB ID) ---

  const wbLookupCache = new Map<string, { data: any; ts: number }>();
  const wbLookupRateMap = new Map<string, number[]>();
  const WB_RATE_LIMIT = 10;
  const WB_RATE_WINDOW = 60_000;
  const WB_CACHE_TTL = 3600_000;

  app.get("/api/whiskybase-lookup/:wbId", async (req: Request, res: Response) => {
    try {
      const wbId = (req.params.wbId as string).trim();
      if (!wbId || wbId.length > 10 || !/^\d+$/.test(wbId)) {
        return res.status(400).json({ error: "Invalid Whiskybase ID (numeric, max 10 digits)" });
      }

      const participantId = req.headers["x-participant-id"] as string | undefined;

      if (participantId) {
        const collection = await storage.getWhiskybaseCollection(participantId);
        const match = collection.find((item: any) => item.whiskybaseId === wbId);
        if (match) {
          return res.json({
            source: "collection",
            name: match.name || "",
            distillery: match.distillery || match.brand || "",
            age: match.statedAge || "",
            abv: match.abv || "",
            caskType: match.caskType || "",
            price: match.pricePaid ? `€${match.pricePaid}` : "",
          });
        }
      }

      const cached = wbLookupCache.get(wbId);
      if (cached && Date.now() - cached.ts < WB_CACHE_TTL) {
        return res.json(cached.data);
      }

      const rateKey = participantId || req.ip || "anon";
      const now = Date.now();
      const history = (wbLookupRateMap.get(rateKey) || []).filter(t => now - t < WB_RATE_WINDOW);
      if (history.length >= WB_RATE_LIMIT) {
        return res.status(429).json({ error: "Too many lookups, please wait" });
      }
      history.push(now);
      wbLookupRateMap.set(rateKey, history);

      const { client, error: aiError, quotaInfo } = await getAIClient(participantId || undefined, "whiskybase_lookup");
      if (!client) {
        if (aiError === "AI_LIMIT_EXCEEDED") return res.status(429).json({ message: "AI_LIMIT_EXCEEDED", error: "AI_LIMIT_EXCEEDED", quotaInfo });
        return res.status(503).json({ error: "ai_unavailable" });
      }

      const completion = await client.chat.completions.create({
        model: "gpt-4o-mini",
        temperature: 0.2,
        response_format: { type: "json_object" },
        messages: [
          {
            role: "system",
            content: `You are a whisky expert with extensive knowledge of the Whiskybase.com database. Given a Whiskybase ID number, return what you know about this whisky. Return JSON with fields: name (full product name), distillery, age (just the number, or "NAS" if no age statement, or empty string if unknown), abv (with % sign or empty string), caskType (e.g. Bourbon, Sherry, Port Pipe, etc.), region (e.g. Islay, Speyside, Highland, Lowland, Islands, Campbeltown, or equivalent for non-Scottish whiskies), country (e.g. Scotland, Ireland, Japan, Germany, USA, etc.), peatLevel (None, Light, Medium, or Heavy), vintage (year as number or empty string), bottler (bottling company name, or "OB" for official bottling, or empty string), price (estimated retail price in EUR with € sign, or empty string). If you don't know a field, return an empty string. If you cannot identify the whisky at all, return {"found": false}.`,
          },
          {
            role: "user",
            content: `Whiskybase ID: ${wbId}`,
          },
        ],
      });

      const raw = completion.choices[0]?.message?.content || "{}";
      const jsonMatch = raw.match(/\{[\s\S]*\}/);
      const parsed = JSON.parse(jsonMatch ? jsonMatch[0] : "{}");

      if (parsed.found === false) {
        return res.status(404).json({ error: "Whisky not found" });
      }

      const result = {
        source: "ai" as const,
        name: parsed.name || "",
        distillery: parsed.distillery || "",
        age: String(parsed.age || ""),
        abv: parsed.abv || "",
        caskType: parsed.caskType || parsed.cask_type || "",
        region: parsed.region || "",
        country: parsed.country || "",
        peatLevel: parsed.peatLevel || parsed.peat_level || "",
        distilledYear: parsed.vintage ? String(parsed.vintage) : "",
        bottler: parsed.bottler || "",
        price: parsed.price || "",
      };

      wbLookupCache.set(wbId, { data: result, ts: Date.now() });
      res.json(result);
    } catch (error: any) {
      console.error("Whiskybase lookup error:", error.message);
      res.status(500).json({ error: "Lookup failed" });
    }
  });

  // --- Auto-fill empty whisky fields using AI ---
  app.post("/api/whisky-autofill", async (req: Request, res: Response) => {
    try {
      const { whiskyName, distillery, emptyFields } = req.body;
      if (!whiskyName && !distillery) {
        return res.status(400).json({ error: "Need at least a whisky name or distillery" });
      }

      const participantId = req.headers["x-participant-id"] as string | undefined;
      const rateKey = participantId || req.ip || "anon";
      const now = Date.now();
      const history = (wbLookupRateMap.get(rateKey) || []).filter(t => now - t < WB_RATE_WINDOW);
      if (history.length >= WB_RATE_LIMIT) {
        return res.status(429).json({ error: "Too many lookups, please wait" });
      }
      history.push(now);
      wbLookupRateMap.set(rateKey, history);

      const { client, error: aiError, quotaInfo } = await getAIClient(participantId || undefined, "whisky_autofill");
      if (!client) {
        if (aiError === "AI_LIMIT_EXCEEDED") return res.status(429).json({ message: "AI_LIMIT_EXCEEDED", error: "AI_LIMIT_EXCEEDED", quotaInfo });
        return res.status(503).json({ error: "ai_unavailable" });
      }

      const fieldsToFill = (emptyFields || []).filter((f: string) =>
        ["age", "abv", "caskType", "region", "country", "peatLevel", "distilledYear", "vintage", "bottler", "price"].includes(f)
      ).map((f: string) => f === "vintage" ? "distilledYear" : f);
      if (fieldsToFill.length === 0) {
        return res.json({});
      }

      const fieldDescriptions: Record<string, string> = {
        age: 'age (just the number, or "NAS" if no age statement)',
        abv: "abv (with % sign)",
        caskType: "caskType (e.g. Bourbon, Sherry, Port Pipe)",
        region: "region (e.g. Islay, Speyside, Highland, Thuringia, etc.)",
        country: "country (e.g. Scotland, Ireland, Japan, Germany, USA)",
        peatLevel: "peatLevel (None, Light, Medium, or Heavy)",
        distilledYear: "distilledYear (year as number)",
        bottler: 'bottler (company name, or "OB" for official bottling)',
        price: "price (estimated retail price in EUR with € sign)",
      };

      const requestedFields = fieldsToFill.map((f: string) => fieldDescriptions[f] || f).join(", ");

      const completion = await client.chat.completions.create({
        model: "gpt-4o-mini",
        temperature: 0.2,
        response_format: { type: "json_object" },
        messages: [
          {
            role: "system",
            content: `You are a whisky expert. Given a whisky name and/or distillery, return your best knowledge about the requested fields. Return JSON with only the requested fields. If you don't know a field, return an empty string. Fields requested: ${requestedFields}`,
          },
          {
            role: "user",
            content: `Whisky: ${whiskyName || "unknown"}${distillery ? `, Distillery: ${distillery}` : ""}`,
          },
        ],
      });

      const raw = completion.choices[0]?.message?.content || "{}";
      const jsonMatch = raw.match(/\{[\s\S]*\}/);
      const parsed = JSON.parse(jsonMatch ? jsonMatch[0] : "{}");

      const result: Record<string, string> = {};
      for (const field of fieldsToFill) {
        const val = parsed[field] || parsed[field.replace(/([A-Z])/g, "_$1").toLowerCase()] || "";
        if (val) result[field] = String(val);
      }

      res.json(result);
    } catch (error: any) {
      console.error("Whisky autofill error:", error.message);
      res.status(500).json({ error: "Autofill failed" });
    }
  });

  // --- Barcode Lookup (EAN/UPC to whisky) ---


  app.get("/api/barcode-lookup/:code", async (req: Request, res: Response) => {
    try {
      const code = (req.params.code as string).trim();
      if (!code || code.length < 8 || code.length > 14 || !/^\d+$/.test(code)) {
        return res.status(400).json({ error: "Invalid barcode (8-14 digits)" });
      }

      const rateLimitKey = (req.headers["x-participant-id"] as string) || (req.ip || req.headers["x-forwarded-for"] || "unknown") as string;
      const rateCheck = checkIdentifyRateLimit(rateLimitKey);
      if (!rateCheck.allowed) {
        return res.status(429).json({ error: "Too many requests.", retryAfter: rateCheck.retryAfterSeconds });
      }

      console.log(`[BARCODE-LOOKUP] code: "${code}"`);

      const { db: dbInst } = await import("./db");
      const { whiskies, whiskybaseCollection } = await import("@shared/schema");
      const { eq, or, ilike } = await import("drizzle-orm");

      const whiskyMatches = await dbInst.select().from(whiskies).where(
        or(
          eq(whiskies.whiskybaseId, code),
          ilike(whiskies.name, code)
        )
      ).limit(1);

      if (whiskyMatches.length > 0) {
        const w = whiskyMatches[0];
        console.log(`[BARCODE-LOOKUP] Found in whiskies table: "${w.name}"`);
        return res.json({
          found: true,
          source: "whisky_db",
          data: {
            name: w.name || "",
            distillery: w.distillery || "",
            region: w.region || "",
            age: w.age || "",
            abv: w.abv ? String(w.abv) : "",
            caskType: w.caskType || "",
            confidence: 95,
          },
        });
      }

      const collectionMatches = await dbInst.select().from(whiskybaseCollection).where(
        or(
          eq(whiskybaseCollection.whiskybaseId, code),
          ilike(whiskybaseCollection.name, code)
        )
      ).limit(1);

      if (collectionMatches.length > 0) {
        const c = collectionMatches[0];
        console.log(`[BARCODE-LOOKUP] Found in collection: "${c.name}"`);
        return res.json({
          found: true,
          source: "collection",
          data: {
            name: c.name || "",
            distillery: c.distillery || c.brand || "",
            region: "",
            age: c.statedAge || "",
            abv: c.abv || "",
            caskType: c.caskType || "",
            confidence: 90,
          },
        });
      }

      console.log(`[BARCODE-LOOKUP] Not found in DB, trying AI text identification...`);
      try {
        const openai = new OpenAI({
          apiKey: process.env.AI_INTEGRATIONS_OPENAI_API_KEY,
          baseURL: process.env.AI_INTEGRATIONS_OPENAI_BASE_URL,
        });

        const completion = await openai.chat.completions.create({
          model: "gpt-4o-mini",
          temperature: 0.1,
          max_tokens: 500,
          response_format: { type: "json_object" },
          messages: [
            {
              role: "system",
              content: `You are a whisky identification expert. Given a barcode number (EAN/UPC), try to identify the whisky product. Return JSON:
{"name": "full product name", "distillery": "distillery name", "age": "age or empty", "abv": "ABV% or empty", "caskType": "cask type or empty", "region": "region or empty", "confidence": "high/medium/low"}
If you cannot identify the barcode, return {"name": "", "confidence": "low"}.`,
            },
            { role: "user", content: `Barcode: ${code}` },
          ],
        });

        const raw = completion.choices[0]?.message?.content || "{}";
        const parsed = JSON.parse(raw);

        if (parsed.name && parsed.confidence !== "low") {
          const confMap: Record<string, number> = { high: 95, medium: 75, low: 45 };
          console.log(`[BARCODE-LOOKUP] AI identified: "${parsed.name}" (${parsed.confidence})`);
          return res.json({
            found: true,
            source: "ai",
            data: {
              name: parsed.name,
              distillery: parsed.distillery || "",
              region: parsed.region || "",
              age: parsed.age || "",
              abv: parsed.abv || "",
              caskType: parsed.caskType || "",
              confidence: confMap[parsed.confidence] || 45,
            },
          });
        }
      } catch (aiErr: any) {
        console.warn("[BARCODE-LOOKUP] AI fallback failed:", aiErr.message);
      }

      console.log(`[BARCODE-LOOKUP] No results for code "${code}"`);
      return res.status(404).json({ found: false, error: "not_found" });
    } catch (error: any) {
      console.error("Barcode lookup error:", error.message);
      res.status(500).json({ error: "Lookup failed" });
    }
  });

