  app.get("/api/collection/:participantId/import-progress", async (req: Request, res: Response) => {
    const participantId = req.params.participantId as string;
    const callerId = req.headers["x-participant-id"] as string | undefined;
    if (!participantId || !callerId || callerId !== participantId) {
      return res.status(403).json({ error: "Forbidden" });
    }
    const progress = importProgressByPid.get(participantId);
    res.json(progress ?? { status: "idle", processed: 0, total: 0 });
  });

  app.post("/api/collection/:participantId/import-progress/cancel", async (req: Request, res: Response) => {
    const participantId = req.params.participantId as string;
    const callerId = req.headers["x-participant-id"] as string | undefined;
    if (!participantId || !callerId || callerId !== participantId) {
      return res.status(403).json({ error: "Forbidden" });
    }
    const cur = importProgressByPid.get(participantId);
    if (!cur || cur.status !== "running") {
      return res.status(409).json({ error: "No running import to cancel" });
    }
    const discard = req.body?.discard === true || req.body?.discard === "true" || req.query.discard === "1";
    importProgressByPid.set(participantId, { ...cur, cancelRequested: true, discardOnCancel: !!discard });
    res.json({ ok: true, discard: !!discard });
  });

  app.post("/api/collection/:participantId/import", docUpload.single("file"), async (req: Request, res: Response) => {
    const participantIdForProgress = req.params.participantId as string;
    try {
      console.log("[Import] Request empfangen", {
        contentType: req.headers["content-type"],
        fileName: req.file?.originalname,
        fileSize: req.file?.size,
        bodyKeys: Object.keys(req.body || {}),
      });

      const participantId = req.params.participantId as string;
      const callerId = req.headers["x-participant-id"] as string | undefined;
      if (!participantId) {
        return res.status(401).json({ error: "Missing participantId" });
      }
      if (!callerId) {
        return res.status(401).json({ error: "Missing x-participant-id header" });
      }
      if (callerId !== participantId) {
        return res.status(403).json({ error: "Forbidden" });
      }

      const file = req.file;
      if (!file) return res.status(400).json({ error: "No file provided" });

      let rows: any[] = [];
      
      const fileName = file.originalname.toLowerCase();
      if (fileName.endsWith(".csv")) {
        const text = file.buffer.toString("utf-8");
        const lines = text.split(/\r?\n/).filter(l => l.trim());
        if (lines.length < 2) return res.status(400).json({ error: "File is empty or has no data rows" });
        
        const headerLine = lines[0];
        const delimiter = headerLine.includes("\t") ? "\t" : headerLine.includes(";") ? ";" : ",";
        
        const parseCSVLine = (line: string, delim: string): string[] => {
          const result: string[] = [];
          let current = "";
          let inQuotes = false;
          for (let i = 0; i < line.length; i++) {
            const char = line[i];
            if (char === '"') {
              if (inQuotes && i + 1 < line.length && line[i + 1] === '"') {
                current += '"';
                i++;
              } else {
                inQuotes = !inQuotes;
              }
            } else if (char === delim && !inQuotes) {
              result.push(current.trim());
              current = "";
            } else {
              current += char;
            }
          }
          result.push(current.trim());
          return result;
        };
        
        const rawHeaders = parseCSVLine(headerLine, delimiter);
        const headerCount: Record<string, number> = {};
        const headers = rawHeaders.map(h => {
          headerCount[h] = (headerCount[h] || 0) + 1;
          return headerCount[h] > 1 ? `${h}_${headerCount[h]}` : h;
        });
        for (let i = 1; i < lines.length; i++) {
          if (!lines[i].trim()) continue;
          const values = parseCSVLine(lines[i], delimiter);
          const row: any = {};
          headers.forEach((h, idx) => { row[h] = values[idx] || ""; });
          rows.push(row);
        }
      } else {
        const workbook = await readExcelBuffer(file.buffer);
        const sheetName = workbook.SheetNames[0];
        rows = sheetToJson(workbook.Sheets[sheetName], { defval: "" });
      }
      
      const colMap = (row: any, ...keys: string[]): string => {
        for (const key of keys) {
          if (row[key] !== undefined && row[key] !== "") return String(row[key]).trim();
        }
        return "";
      };
      
      const parseFloat2 = (val: string): number | null => {
        if (!val) return null;
        const cleaned = val.replace(",", ".");
        const num = parseFloat(cleaned);
        return isNaN(num) ? null : num;
      };
      
      let imported = 0;
      let updated = 0;
      let skipped = 0;
      const addedNames: string[] = [];
      const updatedNames: string[] = [];
      const skippedNames: string[] = [];

      const existingItems = await storage.getWhiskybaseCollection(participantId as string);
      const existingByCollection = new Map(existingItems.filter(item => item.collectionId).map(item => [item.collectionId, item]));
      const existingByWb = new Map(existingItems.map(item => [item.whiskybaseId, item]));

      const tasks: Array<{ isUpdate: boolean; payload: any; previous: any | null }> = [];
      const localEditNames: string[] = [];
      const LOCAL_EDIT_FIELDS = ["status", "personalRating", "notes", "communityRating", "pricePaid", "avgPrice", "auctionPrice"] as const satisfies ReadonlyArray<keyof WhiskybaseCollectionItem>;
      for (const row of rows) {
        const rowName = colMap(row, "Name", "name");
        const whiskybaseId = colMap(row, "ID", "id");
        if (!whiskybaseId) { skipped++; skippedNames.push(rowName || "(unnamed)"); continue; }

        const name = rowName;
        if (!name) { skipped++; skippedNames.push(`ID ${whiskybaseId}`); continue; }

        const collId = colMap(row, "Sammlungs-ID", "Collection ID", "Collection-ID");
        const existing = collId
          ? existingByCollection.get(collId)
          : existingByWb.get(whiskybaseId);
        const isUpdate = !!existing;

        const filePersonalRating = parseFloat2(colMap(row, "Meine Bewertung", "My rating"));
        const fileNotes = colMap(row, "Notizen", "Notes") || null;
        const fileStatus = colMap(row, "Status", "status") || null;

        // Preserve user's local personal fields on overwrite. Only fall back to
        // values from the file when the existing record has no value.
        const personalRating = isUpdate
          ? (existing!.personalRating ?? filePersonalRating)
          : filePersonalRating;
        const notes = isUpdate
          ? (existing!.notes ?? fileNotes)
          : fileNotes;
        const status = isUpdate
          ? (existing!.status ?? fileStatus)
          : fileStatus;

        tasks.push({ isUpdate, previous: existing ? { ...existing } : null, payload: {
          participantId: participantId as string,
          whiskybaseId,
          collectionId: colMap(row, "Sammlungs-ID", "Collection ID", "Collection-ID") || null,
          brand: colMap(row, "Marke", "Brand") || null,
          name,
          bottlingSeries: colMap(row, "Abfüllserie", "Bottling serie", "Bottling series") || null,
          status,
          statedAge: colMap(row, "Deklariertes Alter", "Stated Age") || null,
          size: colMap(row, "Größe", "Size") || null,
          abv: colMap(row, "Stärke", "Strength") || null,
          unit: colMap(row, "Einheit", "Unit") || null,
          caskType: colMap(row, "Fasstyp", "Cask type") || null,
          communityRating: parseFloat2(colMap(row, "Bewertung", "Rating")),
          personalRating,
          pricePaid: parseFloat2(colMap(row, "Bezahlter Preis", "Price paid")),
          currency: colMap(row, "Währung", "Currency") || null,
          avgPrice: parseFloat2(colMap(row, "Mittlerer preis", "Mittlerer Preis", "Average price")),
          avgPriceCurrency: colMap(row, "Währung Whisky", "Currency Whisky") || null,
          distillery: colMap(row, "Destillerien", "Distilleries") || null,
          distilledYear: (() => { const v = colMap(row, "Jahrgang", "Vintage"); return v ? (parseInt(v, 10) || null) : null; })(),
          addedAt: colMap(row, "Hinzugefügt am", "Added on") || null,
          imageUrl: colMap(row, "Bild", "Image") || null,
          auctionPrice: parseFloat2(colMap(row, "Auktionspreis:", "Auction price:", "Auktionspreis", "Auction price")),
          auctionCurrency: colMap(row, "Währung Whisky_2", "Currency Whisky_2") || null,
          notes,
          purchaseLocation: colMap(row, "Kaufort", "Purchase location") || null,
        }});

        if (isUpdate) {
          updatedNames.push(name);
          const localMod = (existing!.locallyModified as Record<string, boolean> | null) || {};
          // Effective values that will actually be written to the row.
          // status/personalRating/notes are preserved when existing has a value,
          // so they only effectively change when existing is null. The numeric
          // and community fields are overwritten directly from the file (incl.
          // null if the file has no value).
          const effectiveByField: Pick<WhiskybaseCollectionItem, typeof LOCAL_EDIT_FIELDS[number]> = {
            status,
            personalRating,
            notes,
            communityRating: parseFloat2(colMap(row, "Bewertung", "Rating")),
            pricePaid: parseFloat2(colMap(row, "Bezahlter Preis", "Price paid")),
            avgPrice: parseFloat2(colMap(row, "Mittlerer preis", "Mittlerer Preis", "Average price")),
            auctionPrice: parseFloat2(colMap(row, "Auktionspreis:", "Auction price:", "Auktionspreis", "Auction price")),
          };
          const existingItem: WhiskybaseCollectionItem = existing!;
          const normalize = (v: unknown) => (v == null || v === "" ? null : v);
          let conflict = false;
          for (const f of LOCAL_EDIT_FIELDS) {
            if (!localMod[f]) continue;
            if (normalize(effectiveByField[f]) !== normalize(existingItem[f])) {
              conflict = true;
              break;
            }
          }
          if (conflict) localEditNames.push(name);
        }
        else addedNames.push(name);
      }

      const dryRun = req.query.dryRun === "1" || req.query.dryRun === "true" || req.body?.dryRun === "1" || req.body?.dryRun === "true";
      if (dryRun) {
        const dryImported = addedNames.length;
        const dryUpdated = updatedNames.length;
        console.log("[Import] Dry-Run", { imported: dryImported, updated: dryUpdated, skipped, total: rows.length, localEdit: localEditNames.length });
        return res.json({ dryRun: true, imported: dryImported, updated: dryUpdated, skipped, total: rows.length, addedNames, updatedNames, skippedNames, localEditNames, localEditCount: localEditNames.length });
      }

      importProgressByPid.set(participantIdForProgress, {
        status: "running",
        processed: 0,
        total: tasks.length,
        startedAt: Date.now(),
      });

      const BATCH_SIZE = 50;
      let cancelled = false;
      const importDetails: Array<{ itemId: string; whiskybaseId: string | null; name: string; action: "added" | "updated"; previous?: Record<string, any> | null }> = [];
      const insertedIds: string[] = [];
      const updatedSnapshots: any[] = [];
      for (let i = 0; i < tasks.length; i += BATCH_SIZE) {
        const beforeBatch = importProgressByPid.get(participantIdForProgress);
        if (beforeBatch?.cancelRequested) { cancelled = true; break; }
        const batch = tasks.slice(i, i + BATCH_SIZE);
        const results = await Promise.all(batch.map(t => storage.upsertWhiskybaseCollectionItem(t.payload)));
        for (let j = 0; j < batch.length; j++) {
          const t = batch[j];
          const result = results[j];
          if (t.isUpdate) {
            updated++;
            if (t.previous) updatedSnapshots.push(t.previous);
            importDetails.push({
              itemId: result.id,
              whiskybaseId: result.whiskybaseId ?? null,
              name: result.name,
              action: "updated",
              previous: t.previous,
            });
          } else {
            imported++;
            if (result?.id) insertedIds.push(result.id);
            importDetails.push({
              itemId: result.id,
              whiskybaseId: result.whiskybaseId ?? null,
              name: result.name,
              action: "added",
            });
          }
        }
        const prev = importProgressByPid.get(participantIdForProgress);
        if (prev?.cancelRequested) { cancelled = true; }
        if (prev) {
          importProgressByPid.set(participantIdForProgress, {
            ...prev,
            processed: Math.min(i + batch.length, tasks.length),
          });
        }
        if (cancelled) break;
      }

      if (cancelled) {
        const startedAt = importProgressByPid.get(participantIdForProgress)?.startedAt ?? Date.now();
        const discardOnCancel = !!importProgressByPid.get(participantIdForProgress)?.discardOnCancel;
        let rolledBackInserts = 0;
        let rolledBackUpdates = 0;
        if (discardOnCancel) {
          for (const id of insertedIds) {
            try {
              await storage.deleteWhiskybaseCollectionItem(id, participantId as string);
              rolledBackInserts++;
            } catch (e: any) {
              console.error("[Import] Rollback delete failed", id, e?.message);
            }
          }
          for (const snap of updatedSnapshots) {
            try {
              await storage.restoreCollectionItemSnapshot(snap);
              rolledBackUpdates++;
            } catch (e: any) {
              console.error("[Import] Rollback restore failed", snap.id, e?.message);
            }
          }
        }
        const keptImported = discardOnCancel ? Math.max(0, imported - rolledBackInserts) : imported;
        const keptUpdated = discardOnCancel ? Math.max(0, updated - rolledBackUpdates) : updated;
        const processed = keptImported + keptUpdated;
        importProgressByPid.set(participantIdForProgress, {
          status: "cancelled",
          processed,
          total: tasks.length,
          imported: keptImported,
          updated: keptUpdated,
          skipped,
          startedAt,
          finishedAt: Date.now(),
          discarded: discardOnCancel,
          rolledBackInserts,
          rolledBackUpdates,
        });
        setTimeout(() => {
          const cur = importProgressByPid.get(participantIdForProgress);
          if (cur && cur.status !== "running") importProgressByPid.delete(participantIdForProgress);
        }, 30_000);
        if (importDetails.length > 0 && !discardOnCancel) {
          try {
            await storage.createCollectionImportLog({
              participantId: participantId as string,
              filename: file.originalname || null,
              summary: { imported: keptImported, updated: keptUpdated, skipped, total: rows.length },
              details: importDetails,
            });
          } catch (logErr: any) {
            console.error("[Import] Failed to write import log (cancelled):", logErr?.message);
          }
        }
        console.log("[Import] Cancelled", { imported: keptImported, updated: keptUpdated, skipped, total: rows.length, processed, discarded: discardOnCancel, rolledBackInserts, rolledBackUpdates });
        return res.json({
          cancelled: true,
          discarded: discardOnCancel,
          imported: keptImported,
          updated: keptUpdated,
          skipped,
          total: rows.length,
          processed,
          rolledBackInserts,
          rolledBackUpdates,
        });
      }

      importProgressByPid.set(participantIdForProgress, {
        status: "completed",
        processed: tasks.length,
        total: tasks.length,
        imported, updated, skipped,
        startedAt: importProgressByPid.get(participantIdForProgress)?.startedAt ?? Date.now(),
        finishedAt: Date.now(),
      });
      setTimeout(() => {
        const cur = importProgressByPid.get(participantIdForProgress);
        if (cur && cur.status !== "running") importProgressByPid.delete(participantIdForProgress);
      }, 30_000);

      let importLogId: string | null = null;
      if (importDetails.length > 0) {
        try {
          const logRow = await storage.createCollectionImportLog({
            participantId: participantId as string,
            filename: file.originalname || null,
            summary: { imported, updated, skipped, total: rows.length },
            details: importDetails,
          });
          importLogId = logRow.id;
        } catch (logErr: any) {
          console.error("[Import] Failed to write import log:", logErr?.message);
        }
      }

      console.log("[Import] Erfolg", { imported, updated, skipped, total: rows.length, importLogId });
      res.json({ imported, updated, skipped, total: rows.length, importLogId });
    } catch (error: any) {
      console.error("[Import] Fehler:", error?.message, error?.stack);
      const prev = importProgressByPid.get(participantIdForProgress);
      importProgressByPid.set(participantIdForProgress, {
        status: "error",
        processed: prev?.processed ?? 0,
        total: prev?.total ?? 0,
        error: error?.message || "Import failed",
        startedAt: prev?.startedAt ?? Date.now(),
        finishedAt: Date.now(),
      });
      setTimeout(() => importProgressByPid.delete(participantIdForProgress), 30_000);
      res.status(500).json({ error: error?.message || "Import failed", details: error?.stack });
    }
  });

